```ts
// LICENSE: MIT
// If anyone would like to use it, or turn it into an NPM package/webpack feature, please do

import fs from "node:fs";
import path from "node:path";
import fastGlob from "fast-glob";
import slash from 'slash';
import type { Compiler } from "webpack";

function isEqualPath(pathA: string, pathB: string) {
	return path.relative(pathA, pathB) === "";
}

function isParentPath(parent: string, child: string): boolean {
	const relative = path.relative(parent, child);

	if (relative === "") {
		return false;
	}

	if (path.isAbsolute(relative)) {
		return false;
	}

	if (relative.startsWith("..")) {
		return false;
	}

	return true;
}

type MultiConfigCleanPluginContextOptions = {
	/**
	 * Absolute path to directory that will be cleaned. Output directory of all Webpack
	 * configurations that use this manager, need to be equal to, or inside this directory.
	 */
	outputPath: string;

	/**
	 * Files that match these glob patterns won't be removed.
	 * @example ["_webpack/cache", "bundle-analyzer.html"]
	 */
	protectPatterns?: string[];

	/**
	 * When `true` plugin will inform about every removed file and directory through logs.
	 * @default false
	 */
	verbose?: boolean;

	/**
	 * When `true` plugin will not remove any files and directories.
	 * @default false
	 */
	dry?: boolean;
};

/**
 * Helper class used by a `MultiConfigCleanWebpackPlugin`.
 * It keep tracks of all generated assets and handles the removal process.
 */
export class MultiConfigCleanPluginContext {
	private readonly options: MultiConfigCleanPluginContextOptions;
	private readonly trackedAssetsByCompiler = new Map<Compiler, string[]>();

	constructor(options: MultiConfigCleanPluginContextOptions) {
		if (!path.isAbsolute(options.outputPath)) {
			throw new Error("Option 'outputPath' needs to an absolute path.");
		}
		if (!isParentPath(process.cwd(), options.outputPath)) {
			throw new Error(
				"Option 'outputPath' can't be a path outside of the current working directory."
			);
		}

		this.options = structuredClone(options);
	}

	private cleanStaleFiles() {
		const PLUGIN_NAME = MultiConfigCleanPluginContext.name;

		const { dry, verbose, protectPatterns, outputPath } = this.options;

		const trackedAssets = new Set(
			[...this.trackedAssetsByCompiler.values()]
				.flat()
				.map((filename) => slash(filename))
		);

		const allFiles = fastGlob.sync("**/*", {
			cwd: outputPath,
			dot: true,
			onlyFiles: true,
			absolute: true,
			ignore: protectPatterns
		});

		const staleFiles = allFiles.filter((filename) => !trackedAssets.has(filename));

		if (staleFiles.length > 0 && verbose === true) {
			console.log(
				`${PLUGIN_NAME}: Following stale files are about to be deleted:`,
				staleFiles.join("\n")
			);
		}

		if (dry !== true) {
			for (const filename of staleFiles) {
				try {
					fs.unlinkSync(filename);
				} catch {
					console.error(`${PLUGIN_NAME}: Couldn't remove a file: '${filename}'.`);
				}
			}
		}
	}

	private cleanEmptyDirectories() {
		const PLUGIN_NAME = MultiConfigCleanPluginContext.name;

		const { dry, verbose, outputPath } = this.options;

		const allDirectories = fastGlob.sync("**/*", {
			cwd: outputPath,
			dot: true,
			onlyDirectories: true,
			absolute: true
		});

		const emptyDirectories = allDirectories.filter((dirname) => {
			return fs.readdirSync(dirname).length === 0;
		});

		if (emptyDirectories.length > 0 && verbose === true) {
			console.log(
				`${PLUGIN_NAME}: Following empty directories are about to be deleted:`,
				emptyDirectories.join("\n")
			);
		}

		if (dry !== true) {
			for (const dirname of emptyDirectories) {
				try {
					fs.rmdirSync(dirname);
				} catch {
					console.error(`${PLUGIN_NAME}: Couldn't remove a directory: '${dirname}'.`);
				}
			}
		}
	}

	registerCompiler(compiler: Compiler) {
		const PLUGIN_NAME = MultiConfigCleanPluginContext.name;

		const mainOutputPath = this.options.outputPath;
		const compilerOutputPath = compiler.options.output.path;

		if (compiler.options.output.clean !== false) {
			throw new TypeError(`Expected 'output.clean' to be 'false'.`);
		}
		if (typeof compilerOutputPath !== "string") {
			throw new TypeError(`Expected 'output.path' to be defined`);
		}

		/*
			Verifies output path of every compiler to make cleaning relatively safe.
		*/
		if (
			!isEqualPath(mainOutputPath, compilerOutputPath) &&
			!isParentPath(mainOutputPath, compilerOutputPath)
		) {
			throw new Error(
				`Expected 'output.path' to be equal to, or to start with '${mainOutputPath}'.`
			);
		}

		/*
			Gets a list of latest assets tracked by given compiler before they are emitted.
			This way there will be no race conditions in which plugin will remove a new asset
			emitted from parallel compilation before finding out that it is now tracked.
		*/
		compiler.hooks.emit.tap(PLUGIN_NAME, (compilation) => {
			const trackedAssets = this.trackedAssetsByCompiler.get(compiler) ?? [];

			/*
				Forgets about previously emitted assets only after a successful compilation.
			*/
			if (compilation.errors.length === 0) {
				trackedAssets.length = 0;
			}

			trackedAssets.push(
				...Object.keys(compilation.assets).map((filename) => {
					return path.resolve(compilerOutputPath, filename);
				})
			);

			this.trackedAssetsByCompiler.set(compiler, trackedAssets);
		});

		/*
			Once compilation is done, and assets are emitted, performs a cleanup.
		*/
		compiler.hooks.done.tap(PLUGIN_NAME, () => {
			this.cleanStaleFiles();
			this.cleanEmptyDirectories();
		});
	}
}

/**
 * When a multi-config Webpack setup is used and output directories of these configs overlap,
 * using a build-in `output.clean` option will lead to unwanted assets deletion, caused by one compiler
 * removing files emitted by other compiler. This plugin can be used to solved that issue. It handles
 * cleanup while keeping all assets emitted by all compilers which use the same context object.
 * @example
 * const srcDir = path.resolve(__dirname, "src");
 * const buildDir = path.resolve(__dirname, "build");
 *
 * const cleanContext = new MultiConfigCleanPluginContext({
 *   outputPath: buildDir
 * });
 *
 * const config = [{
 *   target: "web",
 *   context: srcDir,
 *   entry: {client: "./client.js"},
 *   output: {clean: false, path: buildDir, filename: "[name].js"},
 *   plugins: [
 *     new MultiConfigCleanPlugin(cleanContext)
 *   ]
 * }, {
 *   target: "node",
 *   context: srcDir,
 *   entry: {client: "./server.js"},
 *   output: {clean: false, path: buildDir, filename: "[name].js"},
 *   plugins: [
 *     new MultiConfigCleanPlugin(cleanContext)
 *   ]
 * }];
 */
export class MultiConfigCleanPlugin {
	private readonly manager: MultiConfigCleanPluginContext;

	constructor(manager: MultiConfigCleanPluginContext) {
		this.manager = manager;
	}

	apply(compiler: Compiler) {
		this.manager.registerCompiler(compiler);
	}
}
```

